import React, { useEffect, useState } from "react";
import "./PersonalAIMentor.css";

const firstMessages = {
  INTP: "გამარჯობა 😊 მოდი ერთად გავაანალიზოთ შენი ძლიერი მხარეები.",
  ENFP: "გამარჯობა 🌟 როგორ შემიძლია დაგეხმარო?",
  ENTP: "გამარჯობა 💡 მოდი ვიფიქროთ კრეატიულად!",
  DEFAULT: "გამარჯობა 😊 როგორ შემიძლია დაგეხმარო?"
};

export default function PersonalAIMentor({ userType, userId }) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);

  const mbti = userType || "DEFAULT";

  useEffect(() => {
    if (!userId) return;

    const load = async () => {
      try {
        const res = await fetch(`http://localhost:5000/api/chat-reply/history/${userId}`);
        const data = await res.json();

        if (data.history?.length) setMessages(data.history);
        else setMessages([{ role: "ai", text: firstMessages[mbti] }]);
      } catch {
        setMessages([{ role: "ai", text: firstMessages[mbti] }]);
      }
    };

    load();
  }, [userId, mbti]);

  if (!userId) {
    return <div className="ai-mentor">❗ ჯერ გაიარე login</div>;
  }

  const sendMessage = async () => {
    if (!input.trim()) return;

    const text = input;
    setInput("");
    setMessages(prev => [...prev, { role: "user", text }]);
    setLoading(true);

    try {
      const res = await fetch("http://localhost:5000/api/chat-reply", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          message: text,
          type: mbti,
          userId,
          newChat: false
        })
      });

      const data = await res.json();
      setMessages(prev => [...prev, { role: "ai", text: data.reply }]);
    } catch {
      setMessages(prev => [...prev, { role: "ai", text: "😔 შეცდომა" }]);
    }

    setLoading(false);
  };

  return (
    <div className="ai-mentor">
      <div className="ai-header">AI Mentor ({mbti})</div>

      <div className="ai-messages">
        {messages.map((m, i) => (
          <div key={i} className={`msg ${m.role}`}>
            {m.text}
          </div>
        ))}
      </div>

      <div className="ai-input">
        <textarea
          value={input}
          onChange={e => setInput(e.target.value)}
          placeholder="მომწერე..."
          onKeyDown={e => {
            if (e.key === "Enter" && !e.shiftKey) {
              e.preventDefault();
              sendMessage();
            }
          }}
        />
        <button onClick={sendMessage} disabled={loading}>
          გაგზავნა
        </button>
      </div>
    </div>
  );
}
